class Solution:
    def maxPartitionFactor(self, points):
        n = len(points)
        if n <= 2:
            return 0
        def dist(i, j):
            return abs(points[i][0] - points[j][0]) + abs(points[i][1] - points[j][1])
        best = 0
        for mask in range(1, (1 << n) - 1):
            mono = None
            for i in range(n):
                for j in range(i + 1, n):
                    same = ((mask >> i) & 1) == ((mask >> j) & 1)
                    if same:
                        d = dist(i, j)
                        if mono is None or d < mono:
                            mono = d
            if mono is not None and mono > best:
                best = mono
        return best

