class Solution:
    def maxPartitionFactor(self, points):
        n = len(points)
        if n <= 2:
            return 0
        def dist(i, j):
            return abs(points[i][0] - points[j][0]) + abs(points[i][1] - points[j][1])
        dists = sorted(set(dist(i, j) for i in range(n) for j in range(i + 1, n)))
        def bipartite(t):
            color = [-1] * n
            for s in range(n):
                if color[s] != -1:
                    continue
                color[s] = 0
                stack = [s]
                while stack:
                    u = stack.pop()
                    for v in range(n):
                        if v != u and dist(u, v) < t:
                            if color[v] == -1:
                                color[v] = color[u] ^ 1
                                stack.append(v)
                            elif color[v] == color[u]:
                                return False
            return True
        lo, hi, ans = 0, len(dists) - 1, dists[0]
        while lo <= hi:
            mid = (lo + hi) // 2
            if bipartite(dists[mid]):
                ans = dists[mid]
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

