var maxPartitionFactor = function(points) {
    const n = points.length;
    if (n <= 2) return 0;
    const dist = (i, j) => Math.abs(points[i][0] - points[j][0]) + Math.abs(points[i][1] - points[j][1]);
    const set = new Set();
    for (let i = 0; i < n; i++) for (let j = i + 1; j < n; j++) set.add(dist(i, j));
    const dists = [...set].sort((a, b) => a - b);
    const bipartite = (t) => {
        const color = new Array(n).fill(-1);
        for (let s = 0; s < n; s++) {
            if (color[s] !== -1) continue;
            color[s] = 0;
            const stack = [s];
            while (stack.length) {
                const u = stack.pop();
                for (let v = 0; v < n; v++) {
                    if (v !== u && dist(u, v) < t) {
                        if (color[v] === -1) { color[v] = color[u] ^ 1; stack.push(v); }
                        else if (color[v] === color[u]) return false;
                    }
                }
            }
        }
        return true;
    };
    let lo = 0, hi = dists.length - 1, ans = dists[0];
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (bipartite(dists[mid])) { ans = dists[mid]; lo = mid + 1; }
        else hi = mid - 1;
    }
    return ans;
};
